    def man(a, b): return abs(a[0] - b[0]) + abs(a[1] - b[1])

    # Heuristic: advance toward a resource we can "win" (closer than opponent after move),
    # while keeping distance from the opponent and avoiding moves that let them be equal/advantaged.
    best = None
    best_val = -10**18
    for dx, dy, nx, ny in legal:
        my_after = (nx, ny)
        opp = (ox, oy)

        # Baseline: prefer reducing distance to the closest winnable resource.
        nearest_win = None
        nearest_lose = None
        min_mine = 10**9
        min_theirs = 10**9
        for t in resources:
            dm = man(my_after, t)
            do = man(opp, t)
            if dm < min_mine:
                min_mine = dm
            if do < min_theirs:
                min_theirs = do
            if dm + 1 < do:  # likely win next turn (strictly)
                if nearest_win is None or dm < nearest_win:
                    nearest_win = dm
            elif dm <= do:  # contested or behind
                if nearest_lose is None or dm < nearest_lose:
                    nearest_lose = dm

        # If no winnable resource, still push toward nearest resource but penalize being not ahead.
        if nearest_win is None:
            nearest_win = min_mine
            ahead = 0
        else:
            ahead = 1

        # Opponent pressure: avoid moving into cells that reduce opponent's access advantage.
        # Compute best resource the opponent could take advantage of.
        opp_best = 10**9
        for t in resources[:]:
            d = man(opp, t)
            if d < opp_best:
                opp_best = d

        # Center bias to stay mobile (different from prior "contested" list policy).
        cx, cy = w // 2, h // 2
        center_bias = -(abs(nx - cx) + abs(ny - cy))

        # Main value: reward winning margin and resource proximity; penalize adjacency to opponent.
        margin = 0
        for t in resources:
            dm = man(my_after, t)
            do = man(opp, t)
            if dm <= do:
                margin = max(margin, do - dm)  # positive if we are closer/equal
                break
        opp_dist = man(my_after, opp)
        val = 0
        val += (1000 if ahead else 0)
        val += 500 - 30 * (nearest_win if nearest_win is not None else 0)
        val += 40 * margin
        val += 8 * (opp_best - (min_theirs if min_theirs != 10**9 else opp_best))
        val += 6 * opp_dist
        val += center_bias

        # Strongly avoid stepping directly next to opponent (reduce their capture tempo).
        if opp_dist <= 1:
            val -= 300

        # Deterministic tie-break: fixed ordering of legal list.
        if val > best_val:
            best_val = val
            best = (dx, dy)

    return [int(best[0]), int(best[1])]

